def f(n: int) -> int:
    """Return the number of prime numbers strictly less than n (n ≤ 10 000)."""
    if n <= 2:
        return 0

    # Sieve of Eratosthenes up to n-1
    limit = n
    is_prime = [True] * limit
    is_prime[0:2] = [False, False]  # 0 and 1 are not prime

    for p in range(2, int(limit ** 0.5) + 1):
        if is_prime[p]:
            step = p
            start = p * p
            is_prime[start:limit:step] = [False] * ((limit - start - 1) // step + 1)

    return sum(is_prime)
