def f(expr: str) -> int:
    """Evaluate an arithmetic expression containing non‑negative integers,
    '+', '-', '*', and parentheses.  Operators respect the usual precedence.
    """
    # Remove spaces for easier processing
    s = expr.replace(' ', '')
    n = len(s)
    i = 0

    def parse_number() -> int:
        nonlocal i
        start = i
        while i < n and s[i].isdigit():
            i += 1
        return int(s[start:i])

    def parse_factor() -> int:
        nonlocal i
        if s[i] == '(':
            i += 1                     # skip '('
            val = parse_expr()
            i += 1                     # skip ')'
            return val
        else:
            return parse_number()

    def parse_term() -> int:
        nonlocal i
        val = parse_factor()
        while i < n and s[i] == '*':
            i += 1                     # skip '*'
            val *= parse_factor()
        return val

    def parse_expr() -> int:
        nonlocal i
        val = parse_term()
        while i < n and s[i] in '+-':
            op = s[i]
            i += 1                     # skip operator
            right = parse_term()
            if op == '+':
                val += right
            else:
                val -= right
        return val

    return parse_expr()
